    headers.insert("Authorization".to_string(), format!("Bearer {}", token));
    headers.insert("Content-Type".to_string(), "application/json".to_string());

    match verifier.verify_from_headers(&headers) {
        Ok(user_info) => {
            println!("Verified from headers map - User: {}", user_info.user_id);
        }
        Err(e) => {
            eprintln!("Headers map verification failed: {}", e);
        }
    }

    // Quick verification using convenience function
    match verify_hs256_token(&token, secret) {
        Ok(user_info) => {
            println!("Quick verify - User: {}", user_info.user_id);
        }
        Err(e) => {
            eprintln!("Quick verification failed: {}", e);
        }
    }

    // Check if token is expired
    match verifier.is_token_expired(&token) {
        Ok(expired) => println!("Token expired: {}", expired),
        Err(e) => eprintln!("Could not check expiry: {}", e),
    }

    // Peek at the algorithm
